{"path":"implementation/channels/fengling/static/ops.html","content":"<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>运维 — 风铃</title>
<script src="/static/marked.min.js"></script>
<style>
  :root {
    --bg: #eef6fb;
    --surface: rgba(255, 255, 255, 0.82);
    --surface-alt: #f0f7fb;
    --border: rgba(53, 165, 216, 0.18);
    --text: #1e3040;
    --muted: #6b8fa8;
    --accent: #35a5d8;
    --accent-2: #4cc9a0;
    --green: #28a060;
    --yellow: #d4900a;
    --red: #d94040;
    --blue: #2a7fd4;
  }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: linear-gradient(160deg, #d6eef9 0%, #e8f5f0 55%, #eef6fb 100%);
    background-attachment: fixed;
    color: var(--text);
    font: 14px/1.6 "SF Pro Text", system-ui, sans-serif;
  }

  /* Layout */
  .layout { display: grid; grid-template-columns: 200px 1fr; min-height: 100vh; }
  nav {
    background: rgba(255, 255, 255, 0.78);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border-right: 1px solid var(--border);
    padding: 20px 0;
    position: sticky;
    top: 0;
    height: 100vh;
    overflow-y: auto;
    box-shadow: 2px 0 12px rgba(53, 165, 216, 0.07);
  }
  nav .logo { padding: 0 20px 20px; font-size: 16px; font-weight: 600; border-bottom: 1px solid var(--border); }
  nav .logo span { color: var(--accent); }
  nav ul { list-style: none; margin-top: 8px; }
  nav li a { display: block; padding: 9px 20px; color: var(--muted); text-decoration: none; border-left: 3px solid transparent; transition: all .15s; }
  nav li a:hover, nav li a.active { color: var(--text); background: rgba(53,165,216,.08); border-left-color: var(--accent); }
  main { padding: 24px; overflow-y: auto; }

  /* Header */
  .page-header { display: flex; align-items: center; gap: 12px; margin-bottom: 24px; }
  .page-header h1 { font-size: 20px; font-weight: 600; }
  .refresh-btn { background: none; border: none; color: var(--muted); cursor: pointer; font-size: 15px; padding: 4px 6px; border-radius: 6px; transition: color .15s; line-height: 1; }
  .refresh-btn:hover { color: var(--text); }
  .last-update { color: var(--muted); font-size: 12px; display: flex; align-items: center; gap: 6px; }
  .live-dot { width: 7px; height: 7px; border-radius: 50%; background: #4caf50; animation: pulse-dot 2s infinite; flex-shrink: 0; }
  @keyframes pulse-dot { 0%,100% { opacity: 1; } 50% { opacity: .3; } }

  /* Section */
  section { margin-bottom: 28px; }
  section h2 { font-size: 13px; font-weight: 600; color: var(--muted); text-transform: uppercase; letter-spacing: .06em; margin-bottom: 12px; }

  /* Grid */
  .grid { display: grid; gap: 12px; }
  .grid-2 { grid-template-columns: repeat(2, 1fr); }
  .grid-3 { grid-template-columns: repeat(3, 1fr); }
  .grid-4 { grid-template-columns: repeat(4, 1fr); }
  @media (max-width: 900px) { .grid-4 { grid-template-columns: repeat(2, 1fr); } .grid-3 { grid-template-columns: repeat(2, 1fr); } }

  /* Card */
  .card { background: var(--surface); border: 1px solid var(--border); border-radius: 12px; padding: 16px; backdrop-filter: blur(8px); box-shadow: 0 1px 8px rgba(53,165,216,0.06); }
  .card-title { font-size: 12px; color: var(--muted); margin-bottom: 6px; }
  .card-value { font-size: 24px; font-weight: 600; }
  .card-sub { font-size: 12px; color: var(--muted); margin-top: 2px; }

  /* Status badge */
  .badge { display: inline-flex; align-items: center; gap: 5px; font-size: 12px; padding: 3px 10px; border-radius: 20px; font-weight: 500; }
  .badge::before { content: ''; display: inline-block; width: 7px; height: 7px; border-radius: 50%; }
  .badge-ok { background: rgba(40,160,96,.12); color: var(--green); }
  .badge-ok::before { background: var(--green); }
  .badge-down { background: rgba(217,64,64,.12); color: var(--red); }
  .badge-down::before { background: var(--red); }
  .badge-warn { background: rgba(212,144,10,.12); color: var(--yellow); }
  .badge-warn::before { background: var(--yellow); }

  /* Progress bar */
  .progress { height: 6px; background: rgba(53,165,216,0.15); border-radius: 4px; overflow: hidden; margin-top: 8px; }
  .progress-fill { height: 100%; border-radius: 4px; transition: width .4s; }
  .fill-green { background: var(--green); }
  .fill-yellow { background: var(--yellow); }
  .fill-red { background: var(--red); }

  /* Service row */
  .svc-row { display: flex; align-items: center; justify-content: space-between; padding: 10px 14px; background: var(--surface-alt); border-radius: 8px; margin-bottom: 6px; border: 1px solid var(--border); }
  .svc-name { font-weight: 500; }

  /* Table */
  .table { width: 100%; border-collapse: collapse; font-size: 13px; }
  .table th { text-align: left; padding: 8px 12px; color: var(--muted); font-weight: 500; border-bottom: 1px solid var(--border); background: rgba(53,165,216,0.05); }
  .table td { padding: 9px 12px; border-bottom: 1px solid rgba(53,165,216,.08); vertical-align: top; }
  .table tr:last-child td { border-bottom: none; }
  .table tr:hover td { background: rgba(53,165,216,.04); }
  .table-wrap { background: var(--surface); border: 1px solid var(--border); border-radius: 12px; overflow: hidden; backdrop-filter: blur(8px); box-shadow: 0 1px 8px rgba(53,165,216,0.06); }
  .mono { font-family: "JetBrains Mono", "Fira Code", monospace; font-size: 12px; }

  /* Action btn */
  .btn-del { background: none; border: 1px solid var(--border); color: var(--muted); padding: 3px 10px; border-radius: 6px; cursor: pointer; font-size: 12px; transition: all .15s; }
  .btn-del:hover { border-color: var(--red); color: var(--red); }

  /* State pills */
  .pill { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 11px; font-weight: 600; }
  .pill-running { background: rgba(42,127,212,.12); color: var(--blue); }
  .pill-done { background: rgba(40,160,96,.12); color: var(--green); }
  .pill-failed, .pill-killed { background: rgba(217,64,64,.12); color: var(--red); }
  .pill-error { background: rgba(212,144,10,.12); color: var(--yellow); }

  /* Audit */
  .audit-item { padding: 8px 14px; border-bottom: 1px solid rgba(53,165,216,.08); font-size: 12px; cursor: pointer; }
  .audit-item:last-child { border-bottom: none; }
  .audit-item:hover { background: rgba(53,165,216,.04); }
  .audit-item-row { display: flex; gap: 12px; align-items: baseline; }
  .audit-ts { color: var(--muted); white-space: nowrap; flex-shrink: 0; }
  .audit-evt { font-weight: 600; min-width: 9em; flex-shrink: 0; }
  .audit-evt-chat { color: var(--accent); }
  .audit-evt-timer { color: #7ec8e3; }
  .audit-evt-error { color: var(--red); }
  .audit-evt-stt { color: #a8c97f; }
  .audit-evt-tts { color: #c8a87f; }
  .audit-evt-other { color: var(--muted); }
  .audit-detail { color: var(--text); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; flex: 1; min-width: 0; }
  .audit-expand { display: none; margin-top: 8px; padding: 10px 12px; background: var(--surface-alt); border-radius: 6px; border: 1px solid var(--border); white-space: pre-wrap; word-break: break-all; font-family: monospace; font-size: 11px; line-height: 1.6; color: var(--text); }
  .audit-item.open .audit-expand { display: block; }
  .audit-kv-key { color: var(--muted); }
  .audit-toolbar { display: flex; align-items: center; gap: 10px; padding: 8px 14px; border-bottom: 1px solid var(--border); flex-wrap: wrap; }
  .audit-count { color: var(--muted); font-size: 12px; margin-left: auto; }

  /* Trace */
  .trace-row { cursor: pointer; }
  .trace-row:hover td { background: rgba(53,165,216,.06) !important; }
  .trace-detail { background: var(--surface-alt); border-top: 1px solid var(--border); padding: 16px; display: none; }
  .trace-detail.open { display: block; }
  .step-list { list-style: none; border-left: 2px solid var(--border); margin-left: 8px; padding-left: 16px; }
  .step-list li { padding: 6px 0; font-size: 12px; position: relative; }
  .step-list li::before { content: ''; position: absolute; left: -21px; top: 12px; width: 8px; height: 8px; border-radius: 50%; background: var(--border); }
  .step-llm::before { background: var(--accent) !important; }
  .step-tool::before { background: var(--blue) !important; }
  .step-tag { display: inline-block; padding: 1px 7px; border-radius: 3px; font-size: 11px; margin-right: 6px; }
  .step-tag-llm { background: rgba(53,165,216,.15); color: var(--accent); }
  .step-tag-tool { background: rgba(42,127,212,.15); color: var(--blue); }
  .step-args { color: var(--muted); font-family: monospace; font-size: 11px; margin-top: 3px; word-break: break-all; }
  .step-result { color: var(--text); font-family: monospace; font-size: 11px; margin-top: 3px; background: rgba(53,165,216,.06); border: 1px solid var(--border); padding: 6px 8px; border-radius: 4px; max-height: 120px; overflow-y: auto; white-space: pre-wrap; word-break: break-all; }

  /* Product */
  .skill-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 12px; }
  .skill-card { background: var(--surface); border: 1px solid var(--border); border-radius: 10px; padding: 14px 16px; box-shadow: 0 1px 6px rgba(53,165,216,0.05); }
  .skill-card.always-on { border-color: rgba(53,165,216,.4); }
  .skill-name { font-weight: 600; font-size: 14px; margin-bottom: 4px; display: flex; align-items: center; gap: 8px; }
  .skill-always { font-size: 10px; background: rgba(53,165,216,.15); color: var(--accent); padding: 1px 6px; border-radius: 3px; }
  .skill-desc { font-size: 12px; color: var(--muted); margin-bottom: 8px; }
  .skill-keywords { display: flex; flex-wrap: wrap; gap: 4px; }
  .kw { font-size: 11px; background: rgba(42,127,212,.10); color: var(--blue); padding: 2px 7px; border-radius: 4px; }
  .progress-item { display: flex; gap: 8px; padding: 5px 0; font-size: 13px; border-bottom: 1px solid rgba(53,165,216,.08); }
  .progress-item:last-child { border-bottom: none; }
  .product-section { margin-bottom: 28px; }
  .product-section h2 { font-size: 13px; font-weight: 600; color: var(--muted); text-transform: uppercase; letter-spacing: .06em; margin-bottom: 12px; }
  .focus-item { padding: 6px 14px; border-left: 3px solid var(--accent); margin-bottom: 6px; font-size: 13px; background: rgba(53,165,216,.06); border-radius: 0 6px 6px 0; }
  .caps-body { font-size: 13px; line-height: 1.7; }
  .caps-body h2 { font-size: 13px; font-weight: 600; color: var(--muted); text-transform: uppercase; letter-spacing: .06em; margin: 20px 0 10px; }
  .caps-body h2:first-child { margin-top: 0; }
  .caps-body table { width: 100%; border-collapse: collapse; background: var(--surface); border: 1px solid var(--border); border-radius: 10px; overflow: hidden; margin-bottom: 16px; }
  .caps-body th { text-align: left; padding: 8px 12px; color: var(--muted); font-weight: 500; border-bottom: 1px solid var(--border); font-size: 12px; background: rgba(53,165,216,0.05); }
  .caps-body td { padding: 8px 12px; border-bottom: 1px solid rgba(53,165,216,.08); font-size: 12px; color: var(--text); vertical-align: top; }
  .caps-body tr:last-child td { border-bottom: none; }
  .caps-body tr:hover td { background: rgba(53,165,216,.04); }
  .caps-body a { color: var(--accent); text-decoration: none; }
  .caps-body p { color: var(--muted); margin-bottom: 10px; }
  .caps-body ul { padding-left: 18px; margin-bottom: 10px; }
  .caps-body li { color: var(--muted); margin-bottom: 3px; font-size: 12px; }

  /* Task tree (融合自 tasks.css) */
  .task-tree-wrap { --indent: 22px; }
  .task-tree-wrap .tree-node { position: relative; }
  .task-tree-wrap .tree-children { margin-left: var(--indent); border-left: 1px solid var(--border); overflow: hidden; }
  .task-tree-wrap .tree-children.collapsed { max-height: 0; opacity: 0; pointer-events: none; }
  .task-tree-wrap .tree-children:not(.collapsed) { max-height: 100000px; opacity: 1; transition: opacity .2s; }
  .task-tree-wrap .task-row { display: flex; align-items: center; gap: 6px; padding: 6px 10px; border-radius: 6px; cursor: pointer; user-select: none; min-height: 34px; transition: background .15s; }
  .task-tree-wrap .task-row:hover { background: rgba(53,165,216,.06); }
  .task-tree-wrap .task-row.focus { border-left: 3px solid var(--accent); padding-left: 7px; }
  .task-tree-wrap .toggle-arrow { width: 16px; font-size: 11px; color: var(--muted); flex-shrink: 0; transition: transform .2s; }
  .task-tree-wrap .toggle-arrow.expanded { transform: rotate(90deg); }
  .task-tree-wrap .toggle-arrow.placeholder { visibility: hidden; }
  .task-tree-wrap .status-icon { flex-shrink: 0; font-size: 13px; width: 16px; text-align: center; }
  .task-tree-wrap .status-icon.running { color: #2a7fd4; animation: pulse 2s ease-in-out infinite; }
  .task-tree-wrap .status-icon.completed { color: #28a060; }
  .task-tree-wrap .status-icon.failed { color: #d94040; }
  .task-tree-wrap .status-icon.waiting { color: #d4900a; }
  .task-tree-wrap .status-icon.queued { color: #6b8fa8; }
  .task-tree-wrap .status-icon.cancelled { color: #9ab0be; }
  .task-tree-wrap .task-title { flex: 1; font-size: 13px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
  .task-tree-wrap .state-badge { padding: 1px 7px; border-radius: 4px; font-size: 11px; font-weight: 500; flex-shrink: 0; }
  .task-tree-wrap .state-badge.running { background: rgba(42,127,212,.12); color: #2a7fd4; }
  .task-tree-wrap .state-badge.completed { background: rgba(40,160,96,.12); color: #28a060; }
  .task-tree-wrap .state-badge.failed { background: rgba(217,64,64,.12); color: #d94040; }
  .task-tree-wrap .state-badge.waiting { background: rgba(212,144,10,.12); color: #d4900a; }
  .task-tree-wrap .state-badge.queued { background: rgba(107,143,168,.12); color: #6b8fa8; }
  .task-tree-wrap .state-badge.cancelled { background: rgba(154,176,190,.12); color: #9ab0be; }
  .task-tree-wrap .progress-counter,.task-tree-wrap .focus-tag { font-size: 11px; color: var(--muted); flex-shrink: 0; }
  .task-tree-wrap .focus-tag { color: var(--accent); }
  .task-tree-wrap .task-detail { overflow: hidden; max-height: 0; opacity: 0; transition: max-height .3s, opacity .2s; margin-left: 44px; border-left: 2px solid var(--border); }
  .task-tree-wrap .task-detail.open { max-height: 2000px; opacity: 1; padding: 8px 4px 12px 12px; }
  .task-tree-wrap .detail-field { font-size: 12px; line-height: 1.6; color: var(--muted); margin-bottom: 8px; }
  .task-tree-wrap .detail-label { font-size: 11px; font-weight: 600; text-transform: uppercase; letter-spacing: .4px; margin-bottom: 2px; }
  .task-tree-wrap .detail-value { color: var(--text); }
  .task-tree-wrap .detail-field.error .detail-value { color: #d94040; }
  .task-tree-wrap .detail-actions { display: flex; gap: 6px; margin-top: 6px; flex-wrap: wrap; }
  .task-tree-wrap .detail-actions button { padding: 3px 10px; border-radius: 4px; border: 1px solid var(--border); background: rgba(255,255,255,0.7); color: var(--text); cursor: pointer; font-size: 11px; }
  .task-tree-wrap .detail-actions button:hover { background: rgba(53,165,216,.08); border-color: var(--accent); }
  .task-tree-wrap .detail-actions button.danger { border-color: #d94040; color: #d94040; }
  .task-tree-wrap .markdown-body { font-size: 12px; line-height: 1.6; }
  .task-tree-wrap .markdown-body p { margin: 0 0 6px; }
  .task-tree-wrap .markdown-body code { font-family: monospace; font-size: 11px; padding: 1px 4px; background: rgba(53,165,216,.08); border-radius: 3px; }
  .task-legend { display: flex; gap: 14px; flex-wrap: wrap; padding: 10px 0; margin-bottom: 12px; font-size: 12px; color: var(--muted); }
  .task-legend-item { display: flex; align-items: center; gap: 4px; }
  .task-dot { width: 9px; height: 9px; border-radius: 50%; display: inline-block; }
  @keyframes pulse { 0%,100% { opacity:1; } 50% { opacity:.45; } }

  /* Memory */
  .mem-section { margin-bottom: 20px; }
  .mem-section-title { font-size: 13px; font-weight: 600; color: var(--accent); margin-bottom: 8px; display: flex; align-items: center; gap: 6px; }
  .mem-item { padding: 6px 12px; border-left: 2px solid var(--border); margin-bottom: 4px; font-size: 13px; line-height: 1.5; color: var(--text); transition: border-color .15s; }
  .mem-item:hover { border-left-color: var(--accent); }
  .mem-date { font-size: 11px; color: var(--muted); font-family: monospace; margin-right: 6px; }
  .daily-log { background: var(--surface); border: 1px solid var(--border); border-radius: 10px; padding: 14px 16px; margin-bottom: 14px; box-shadow: 0 1px 6px rgba(53,165,216,0.05); }
  .daily-log-date { font-size: 12px; color: var(--muted); font-weight: 600; margin-bottom: 8px; }
  .daily-log-content { font-size: 13px; white-space: pre-wrap; line-height: 1.6; color: var(--text); }

  /* Empty */
  .empty { text-align: center; color: var(--muted); padding: 28px; font-size: 13px; }

  /* Section nav panel */
  .panel { display: none; }
  .panel.active { display: block; }

  /* Spinner */
  @keyframes spin { to { transform: rotate(360deg); } }
  .spinning { animation: spin .8s linear infinite; display: inline-block; }
</style>
</head>
<body>
<div class="layout">
  <nav>
    <div class="logo">🎐 <span>风铃</span> 运维</div>
    <ul>
      <li><a href="#" data-panel="overview" class="active">📊 概览</a></li>
      <li><a href="#" data-panel="services">🔌 服务状态</a></li>
      <li><a href="#" data-panel="system">💻 系统资源</a></li>
      <li><a href="#" data-panel="timers">⏰ 提醒队列</a></li>
      <li><a href="#" data-panel="watchlist">👁 订阅监控</a></li>
      <li><a href="#" data-panel="processes">⚙️ 后台进程</a></li>
      <li><a href="#" data-panel="sessions">💬 会话</a></li>
      <li><a href="#" data-panel="audit">📋 审计日志</a></li>
      <li><a href="#" data-panel="traces">🔍 执行详情</a></li>
      <li><a href="#" data-panel="memory">🧠 记忆</a></li>
      <li><a href="#" data-panel="product">📦 产品</a></li>
      <li><a href="#" data-panel="tasks">📋 任务图</a></li>
      <li><a href="#" data-panel="methodology">🏛 方法论</a></li>
    </ul>
  </nav>

  <main>
    <div class="page-header">
      <h1 id="panel-title">概览</h1>
      <span class="last-update" id="last-update"><span class="live-dot"></span><span id="last-update-text">--</span></span>
      <button class="refresh-btn" id="btn-refresh" title="立即刷新">↻</button>
    </div>

    <!-- Overview -->
    <div class="panel active" id="panel-overview">
      <section>
        <h2>核心服务</h2>
        <div class="grid grid-4" id="svc-cards"></div>
      </section>
      <section>
        <h2>系统资源</h2>
        <div class="grid grid-3" id="sys-cards"></div>
      </section>
      <section>
        <h2>活跃任务概览</h2>
        <div class="grid grid-4" id="activity-cards"></div>
      </section>
    </div>

    <!-- Services -->
    <div class="panel" id="panel-services">
      <div class="card">
        <div id="svc-list"></div>
      </div>
    </div>

    <!-- System -->
    <div class="panel" id="panel-system">
      <div class="grid grid-3" id="sys-detail"></div>
    </div>

    <!-- Timers -->
    <div class="panel" id="panel-timers">
      <section>
        <h2>定时提醒（EventBus）</h2>
        <div class="table-wrap">
          <table class="table">
            <thead><tr><th>消息</th><th>语义意图</th><th>触发时间</th><th>剩余</th><th>会话</th><th></th></tr></thead>
            <tbody id="timers-body"></tbody>
          </table>
          <div class="empty hidden" id="timers-empty">当前没有待触发的提醒</div>
        </div>
      </section>
      <section style="margin-top:24px">
        <h2>日历提醒（农历/节日）</h2>
        <div class="table-wrap">
          <table class="table">
            <thead><tr><th>消息</th><th>类型</th><th>下次触发</th><th>上次通知</th><th></th></tr></thead>
            <tbody id="cal-reminders-body"></tbody>
          </table>
          <div class="empty hidden" id="cal-reminders-empty">没有日历类提醒</div>
        </div>
      </section>
    </div>

    <!-- Watchlist -->
    <div class="panel" id="panel-watchlist">
      <div class="table-wrap">
        <table class="table">
          <thead><tr><th>主题</th><th>关键词</th><th>间隔</th><th>上次检查</th><th></th></tr></thead>
          <tbody id="watchlist-body"></tbody>
        </table>
        <div class="empty hidden" id="watchlist-empty">没有订阅项</div>
      </div>
    </div>

    <!-- Processes -->
    <div class="panel" id="panel-processes">
      <div class="table-wrap">
        <table class="table">
          <thead><tr><th>PID</th><th>标签</th><th>状态</th><th>耗时</th><th>命令</th><th></th></tr></thead>
          <tbody id="proc-body"></tbody>
        </table>
        <div class="empty hidden" id="proc-empty">没有后台进程</div>
      </div>
    </div>

    <!-- Sessions -->
