<script>
let _data = null;
let _traces = [];

// ── Navigation ────────────────────────────────────────────────
const TITLES = {
  overview: '概览', services: '服务状态', system: '系统资源',
  timers: '提醒队列', watchlist: '订阅监控', processes: '后台进程',
  sessions: '会话', audit: '审计日志', traces: '执行详情',
  memory: '记忆', product: '产品', tasks: '任务图', methodology: '方法论',
};

document.querySelectorAll('nav a').forEach(a => {
  a.addEventListener('click', e => {
    e.preventDefault();
    document.querySelectorAll('nav a').forEach(x => x.classList.remove('active'));
    a.classList.add('active');
    const panel = a.dataset.panel;
    document.querySelectorAll('.panel').forEach(p => p.classList.remove('active'));
    document.getElementById('panel-' + panel).classList.add('active');
    document.getElementById('panel-title').textContent = TITLES[panel];
    if (panel === 'traces') { loadTraceDates(); loadTraces(); return; }
    if (panel === 'audit') { loadAuditDates(); loadAudit(); return; }
    if (panel === 'memory') { loadMemory(); return; }
    if (panel === 'product') { loadProduct(); return; }
    if (panel === 'tasks') { loadTasksPanel(); return; }
    if (panel === 'methodology') { loadMethodologyPanel(); return; }
    if (_data) render(panel, _data);
  });
});

// ── Fetch ─────────────────────────────────────────────────────
async function fetchData() {
  const btn = document.getElementById('btn-refresh');
  btn.innerHTML = '<span class="spinning">↻</span> 刷新';
  btn.disabled = true;
  try {
    const r = await fetch('/api/ops/status');
    _data = await r.json();
    render(activePanel(), _data);
    document.getElementById('last-update-text').textContent = '更新于 ' + new Date().toLocaleTimeString('zh-CN');
  } catch(e) {
    document.getElementById('last-update-text').textContent = '⚠️ 加载失败：' + e.message;
  } finally {
    btn.innerHTML = '↻ 刷新';
    btn.disabled = false;
  }
}

document.getElementById('btn-refresh').addEventListener('click', fetchData);

// ── Helpers ───────────────────────────────────────────────────
function activePanel() {
  const active = document.querySelector('.panel.active');
  return active ? active.id.replace('panel-', '') : 'overview';
}

function badge(status) {
  const cls = status === 'ok' ? 'badge-ok' : status === 'down' ? 'badge-down' : 'badge-warn';
  const label = status === 'ok' ? '正常' : status === 'down' ? '离线' : '异常';
  return `<span class="badge ${cls}">${label}</span>`;
}

function pill(state) {
  return `<span class="pill pill-${state}">${state}</span>`;
}

function humanSeconds(s) {
  s = Math.round(s);
  if (s < 0) return '已过期';
  if (s < 60) return s + 's';
  if (s < 3600) {
    const m = Math.floor(s / 60), sec = s % 60;
    return m + 'm' + (sec ? ' ' + sec + 's' : '');
  }
  if (s < 86400) {
    const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60);
    return h + 'h' + (m ? ' ' + m + 'm' : '');
  }
  const days = Math.floor(s / 86400);
  if (days < 30) {
    const h = Math.floor((s % 86400) / 3600);
    return days + '天' + (h ? h + '小时' : '');
  }
  // Very large (e.g. cron with next trigger in months): show approximate date
  const d = new Date(Date.now() + s * 1000);
  return d.toLocaleDateString('zh-CN', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' });
}

function humanElapsed(s) {
  s = Math.round(s);
  const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), sec = s % 60;
  return (h ? h + 'h ' : '') + (m ? m + 'm ' : '') + sec + 's';
}

function progressColor(pct) {
  return pct > 85 ? 'fill-red' : pct > 60 ? 'fill-yellow' : 'fill-green';
}

function metricCard(title, value, sub, pct) {
  const bar = pct != null ? `<div class="progress"><div class="progress-fill ${progressColor(pct)}" style="width:${pct}%"></div></div>` : '';
  return `<div class="card"><div class="card-title">${title}</div><div class="card-value">${value}</div><div class="card-sub">${sub}</div>${bar}</div>`;
}

function formatTs(iso) {
  if (!iso) return '—';
  try { return new Date(iso * 1000).toLocaleString('zh-CN'); } catch { return iso; }
}

async function apiDelete(url, onSuccess) {
  try {
    const r = await fetch(url, { method: 'DELETE' });
    const j = await r.json();
    if (j.ok !== false) { onSuccess(); fetchData(); }
    else alert('操作失败：' + (j.error || ''));
  } catch(e) { alert('请求失败：' + e); }
}

// ── Render ────────────────────────────────────────────────────
function render(panel, d) {
  if (panel === 'overview') renderOverview(d);
  else if (panel === 'services') renderServices(d);
  else if (panel === 'system') renderSystem(d);
  else if (panel === 'timers') renderTimers(d);
  else if (panel === 'watchlist') renderWatchlist(d);
  else if (panel === 'processes') renderProcesses(d);
  else if (panel === 'sessions') renderSessions(d);
  else if (panel === 'audit') renderAudit(d);
  else if (panel === 'traces') loadTraces();
  else if (panel === 'memory') loadMemory();
  else if (panel === 'product') loadProduct();
  else if (panel === 'tasks') loadTasksPanel();
}

function renderOverview(d) {
  // Service cards
  const svcNames = {
    fengling: '🎐 风铃',
    stt_proxy: '🎤 STT 代理',
    timer_api: '⏰ Timer API',
    'openrouter-proxy': '💻 Code 能力'
  };
  document.getElementById('svc-cards').innerHTML =
    Object.entries(svcNames).map(([k, label]) => {
      const status = d.services?.[k] || 'unknown';
      return `<div class="card"><div class="card-title">${label}</div><div style="margin-top:4px">${badge(status)}</div></div>`;
    }).join('');

  // System cards
  const s = d.system || {};
  document.getElementById('sys-cards').innerHTML = s.mem_total_gb ? [
    metricCard('CPU', s.cpu_pct + '%', '使用率', s.cpu_pct),
    metricCard('内存', s.mem_pct + '%', `${s.mem_used_gb} / ${s.mem_total_gb} GB`, s.mem_pct),
    metricCard('磁盘', s.disk_pct + '%', `${s.disk_used_gb} / ${s.disk_total_gb} GB`, s.disk_pct),
  ].join('') : '<div class="card"><div class="empty">psutil 未安装</div></div>';

  // Activity summary
  document.getElementById('activity-cards').innerHTML = [
    metricCard('⏰ 待触发提醒', (d.timers || []).length, '个'),
    metricCard('🗓 日历提醒', (d.calendar_reminders || []).length, '个'),
    metricCard('👁 监控订阅', (d.watchlist || []).length, '个'),
    metricCard('⚙️ 后台进程', (d.processes || []).length, '个'),
  ].join('');
}

function renderServices(d) {
  const svcNames = {
    fengling: '🎐 风铃 (主服务)',
    stt_proxy: '🎤 STT 代理 (:8787)',
    timer_api: '⏰ Timer API (:8789)',
    'openrouter-proxy': '💻 Code 能力 (OpenRouter Proxy :9999)'
  };
  document.getElementById('svc-list').innerHTML =
    Object.entries(svcNames).map(([k, label]) => {
      const status = d.services?.[k] || 'unknown';
      return `<div class="svc-row"><span class="svc-name">${label}</span>${badge(status)}</div>`;
    }).join('') || '<div class="empty">暂无数据</div>';
}

function renderSystem(d) {
  const s = d.system || {};
  if (!s.mem_total_gb) {
    document.getElementById('sys-detail').innerHTML = '<div class="card"><div class="empty">psutil 未安装，无法获取系统资源数据</div></div>';
    return;
  }
  document.getElementById('sys-detail').innerHTML = [
    metricCard('CPU 使用率', s.cpu_pct + '%', '实时', s.cpu_pct),
    metricCard('内存', `${s.mem_pct}%`, `${s.mem_used_gb} / ${s.mem_total_gb} GB`, s.mem_pct),
    metricCard('磁盘', `${s.disk_pct}%`, `${s.disk_used_gb} / ${s.disk_total_gb} GB`, s.disk_pct),
  ].join('');
}

function renderTimers(d) {
  const timers = d.timers || [];
  const tbody = document.getElementById('timers-body');
  const empty = document.getElementById('timers-empty');
  if (!timers.length) { tbody.innerHTML = ''; empty.classList.remove('hidden'); return; }
  empty.classList.add('hidden');
  tbody.innerHTML = timers.map(t => {
    const msg = (t.payload?.message || '').substring(0, 60);
    const fireAt = t.fire_at ? new Date(t.fire_at * 1000).toLocaleString('zh-CN') : '—';
    const rem = humanSeconds(t.remaining_seconds || 0);
    // Build intent cell from intent field (with fallback to legacy type)
    const intent = t.intent || {};
    let intentCell;
    if (intent.type === 'recurring' || t.type === 'cron') {
      const lbl = intent.human || t.label || t.cron_expr || '';
      intentCell = `<td><span style="color:#4caf93;font-weight:600">🔄 周期</span><br><span class="mono" style="font-size:11px;color:var(--muted)">${lbl}</span></td>`;
    } else {
      intentCell = `<td><span style="color:var(--muted)">⏱ 一次性</span></td>`;
    }
    return `<tr>
      <td>${msg}</td>
      ${intentCell}
      <td class="mono">${fireAt}</td>
      <td>${rem}</td>
      <td class="mono" style="font-size:11px;color:var(--muted)">${t.session_key || '—'}</td>
      <td><button class="btn-del" onclick="apiDelete('/api/ops/timers/${t.id}', ()=>{})">取消</button></td>
    </tr>`;
  }).join('');

  // Render calendar reminders
  renderCalendarReminders(d);
}

function _calNextDate(entry) {
  // 优先使用服务端预计算的精确触发日期
  if (entry.next_trigger_date) {
    const timeStr = entry.time || '09:00';
    return `${entry.next_trigger_date} ${timeStr}`;
  }
  // 降级：solar_date 客户端计算
  const advDays = parseInt(entry.advance_days || 0);
  const intentType = entry.type;
  const timeStr = entry.time || '09:00';
  if (intentType === 'holiday') {
    const name = entry.name || '节日';
    const adv = advDays > 0 ? `提前${advDays}天 ` : '';
    return `${name} ${adv}${timeStr}`;
  } else if (intentType === 'lunar_date') {
    const lm = entry.lunar_month, ld = entry.lunar_day;
    const adv = advDays > 0 ? `提前${advDays}天 ` : '';
    return `农历${lm}月${ld}日 ${adv}${timeStr}`;
  } else if (intentType === 'solar_date') {
    const sm = entry.solar_month, sd = entry.solar_day;
    const now = new Date();
    const thisYear = now.getFullYear();
    let target = new Date(thisYear, sm - 1, sd);
    const remindDate = new Date(target.getTime() - advDays * 86400000);
    if (remindDate < now) {
      target = new Date(thisYear + 1, sm - 1, sd);
    }
    const triggerDate = new Date(target.getTime() - advDays * 86400000);
    const dateStr = triggerDate.toLocaleDateString('zh-CN', { year: 'numeric', month: 'numeric', day: 'numeric' });
    return `${dateStr} ${timeStr}`;
  }
  return '—';
}

function renderCalendarReminders(d) {
  const reminders = d.calendar_reminders || [];
  const tbody = document.getElementById('cal-reminders-body');
  const empty = document.getElementById('cal-reminders-empty');
  if (!tbody) return;
  if (!reminders.length) { tbody.innerHTML = ''; empty.classList.remove('hidden'); return; }
  empty.classList.add('hidden');
  tbody.innerHTML = reminders.map(r => {
    const msg = (r.message || '').substring(0, 60);
    let typeCell;
    if (r.type === 'holiday') {
      const name = r.name || '节日';
      const adv = parseInt(r.advance_days || 0);
      typeCell = `<td><span style="color:#f4c430;font-weight:600">🏮 ${name}</span>${adv > 0 ? `<br><span style="font-size:11px;color:var(--muted)">提前${adv}天</span>` : ''}</td>`;
    } else if (r.type === 'lunar_date') {
      const lm = r.lunar_month, ld = r.lunar_day;
      const adv = parseInt(r.advance_days || 0);
      const lbl = r.label || `农历${lm}月${ld}日`;
      typeCell = `<td><span style="color:#c8a4ff;font-weight:600">🌙 ${lbl}</span>${adv > 0 ? `<br><span style="font-size:11px;color:var(--muted)">提前${adv}天</span>` : ''}</td>`;
    } else if (r.type === 'solar_date') {
      const sm = r.solar_month, sd = r.solar_day;
      const adv = parseInt(r.advance_days || 0);
      const lbl = r.label || `每年${sm}月${sd}日`;
      typeCell = `<td><span style="color:#f4a261;font-weight:600">☀️ ${lbl}</span>${adv > 0 ? `<br><span style="font-size:11px;color:var(--muted)">提前${adv}天</span>` : ''}</td>`;
    } else {
      typeCell = `<td>—</td>`;
    }
    const nextTrigger = _calNextDate(r);
    const lastNotified = r.last_notified_date || '从未';
    return `<tr>
      <td>${msg}</td>
      ${typeCell}
      <td style="color:var(--muted);font-size:12px">${nextTrigger}</td>
      <td style="color:var(--muted);font-size:12px">${lastNotified}</td>
      <td><button class="btn-del" onclick="apiDelete('/api/ops/calendar-reminders/${r.id}', ()=>{})">取消</button></td>
    </tr>`;
  }).join('');
}

function renderWatchlist(d) {
  const list = d.watchlist || [];
  const tbody = document.getElementById('watchlist-body');
  const empty = document.getElementById('watchlist-empty');
  if (!list.length) { tbody.innerHTML = ''; empty.classList.remove('hidden'); return; }
  empty.classList.add('hidden');
  tbody.innerHTML = list.map(w => {
    const checked = w.last_checked_at && w.last_checked_at !== '1970-01-01T00:00:00+00:00'
      ? new Date(w.last_checked_at).toLocaleString('zh-CN') : '从未';
    return `<tr>
      <td>${w.topic}</td>
      <td class="mono">${w.query}</td>
      <td>${w.interval_hours}h</td>
      <td style="color:var(--muted);font-size:12px">${checked}</td>
      <td><button class="btn-del" onclick="apiDelete('/api/ops/watchlist/${w.watch_id}', ()=>{})">删除</button></td>
    </tr>`;
  }).join('');
}

function renderProcesses(d) {
  const procs = d.processes || [];
  const tbody = document.getElementById('proc-body');
  const empty = document.getElementById('proc-empty');
  if (!procs.length) { tbody.innerHTML = ''; empty.classList.remove('hidden'); return; }
  empty.classList.add('hidden');
  tbody.innerHTML = procs.map(p => `<tr>
    <td class="mono">${p.pid}</td>
    <td>${p.label}</td>
    <td>${pill(p.state)}</td>
    <td>${humanElapsed(p.elapsed_sec)}</td>
    <td class="mono" style="max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${p.command}">${p.command}</td>
    <td>${p.state === 'running' ? `<button class="btn-del" onclick="apiDelete('/api/ops/processes/${p.pid}', ()=>{})">终止</button>` : ''}</td>
  </tr>`).join('');
}

function renderSessions(d) {
  const sessions = d.sessions || [];
  const tbody = document.getElementById('sessions-body');
  const empty = document.getElementById('sessions-empty');
  if (!sessions.length) { tbody.innerHTML = ''; empty.classList.remove('hidden'); return; }
  empty.classList.add('hidden');
  tbody.innerHTML = sessions.map(s => `<tr>
    <td class="mono">${s.key}</td>
    <td>${s.messages}</td>
    <td style="color:var(--muted);font-size:12px">${formatTs(s.mtime)}</td>
    <td><button class="btn-del" onclick="apiDelete('/api/ops/sessions/${encodeURIComponent(s.key)}', ()=>{})">清空</button></td>
  </tr>`).join('');
}

function _auditEvtClass(evt) {
  if (evt.includes('error')) return 'audit-evt-error';
  if (evt === 'chat') return 'audit-evt-chat';
  if (evt.startsWith('timer')) return 'audit-evt-timer';
  if (evt === 'stt') return 'audit-evt-stt';
  if (evt === 'tts' || evt === 'tts_stream') return 'audit-evt-tts';
  return 'audit-evt-other';
}

function _auditDetail(e) {
  // Summary line: priority fields, truncated for one-line display
  const SKIP = new Set(['ts', 'event', 'channel']);
  const PRIORITY = ['user', 'message', 'text', 'session', 'session_key', 'timer_id'];
  const all = Object.entries(e).filter(([k]) => !SKIP.has(k));
  const prio = PRIORITY.map(k => all.find(([ak]) => ak === k)).filter(Boolean);
  const rest = all.filter(([k]) => !PRIORITY.includes(k));
  return [...prio, ...rest]
    .map(([k, v]) => {
      const vs = typeof v === 'string' ? v.substring(0, 60) : String(v).substring(0, 40);
      return `<span class="audit-kv-key">${k}=</span>${vs.replace(/</g,'&lt;').replace(/>/g,'&gt;')}`;
    })
    .join('<span style="color:var(--border)">  </span>');
}

function _auditExpand(e) {
  // Full JSON, with long string fields expanded (not truncated)
  const SKIP = new Set(['ts', 'event', 'channel']);
  const PRIORITY = ['user', 'message', 'text', 'assistant', 'error', 'session', 'session_key', 'timer_id'];
  const all = Object.entries(e).filter(([k]) => !SKIP.has(k));
  const prio = PRIORITY.map(k => all.find(([ak]) => ak === k)).filter(Boolean);
  const rest = all.filter(([k]) => !PRIORITY.includes(k));
  return [...prio, ...rest]
    .map(([k, v]) => {
      const vs = typeof v === 'string'
        ? v.replace(/</g,'&lt;').replace(/>/g,'&gt;')
        : JSON.stringify(v, null, 2).replace(/</g,'&lt;').replace(/>/g,'&gt;');
      return `<span class="audit-kv-key">${k}</span>: ${vs}`;
    })
    .join('\n');
}

let _auditOpen = new Set(); // persist open state across re-renders

function toggleAuditItem(el) {
  const id = el.dataset.auditId;
  if (el.classList.toggle('open')) _auditOpen.add(id);
  else _auditOpen.delete(id);
}

function renderAudit(d) {
  const entries = d.audit || [];
  _renderAuditEntries(entries, null);
}

function _renderAuditEntries(entries, total) {
  const list = document.getElementById('audit-list');
  const empty = document.getElementById('audit-empty');
  const countEl = document.getElementById('audit-count');
  if (countEl) {
    if (total != null) countEl.textContent = `显示 ${entries.length} / ${total} 条`;
    else if (entries.length) countEl.textContent = `${entries.length} 条`;
    else countEl.textContent = '';
  }
  if (!entries.length) { list.innerHTML = ''; empty.classList.remove('hidden'); return; }
  empty.classList.add('hidden');
  list.innerHTML = entries.map(e => {
    const ts = e.ts ? new Date(e.ts).toLocaleTimeString('zh-CN') : '—';
    const evt = e.event || '';
    const evtCls = _auditEvtClass(evt);
    const isError = evtCls === 'audit-evt-error';
    const detail = _auditDetail(e);
    const expand = _auditExpand(e);
    const auditId = (e.ts || '') + '|' + (e.event || '') + '|' + (e.timer_id || e.session || '');
    const isOpen = _auditOpen.has(auditId);
    return `<div class="audit-item${isOpen ? ' open' : ''}" data-audit-id="${auditId}" style="${isError ? 'background:rgba(248,113,113,.05)' : ''}" onclick="toggleAuditItem(this)">
      <div class="audit-item-row">
        <span class="audit-ts">${ts}</span>
        <span class="audit-evt ${evtCls}">${evt}</span>
        <span class="audit-detail">${detail}</span>
      </div>
      <div class="audit-expand">${expand}</div>
    </div>`;
  }).join('');
}

async function loadAudit() {
  const date = document.getElementById('audit-date-picker')?.value || '';
  const url = '/api/audit' + (date ? '?date=' + date : '');
  try {
    const r = await fetch(url);
    const j = await r.json();
    const entries = (j.entries || []).reverse(); // newest first
    _renderAuditEntries(entries, j.count);
  } catch(e) {
    document.getElementById('audit-count').textContent = '加载失败';
  }
}

async function loadAuditDates() {
  try {
    const r = await fetch('/api/audit/dates');
    if (!r.ok) return;
    const j = await r.json();
    const picker = document.getElementById('audit-date-picker');
    const existing = new Set([...picker.options].map(o => o.value));
    (j.dates || []).forEach(d => {
      if (!existing.has(d)) {
        const opt = document.createElement('option');
        opt.value = d; opt.textContent = d;
        picker.appendChild(opt);
      }
    });
  } catch(_) {}
}

