let _tracesOpen = new Set(); // persist open state across re-renders

async function loadTraceDates() {
  try {
    const r = await fetch('/api/ops/traces/dates');
    const j = await r.json();
    const picker = document.getElementById('traces-date-picker');
    const currentVal = picker.value;
    // Rebuild options: keep "今日" + archived dates
    picker.innerHTML = '<option value="">今日（实时）</option>';
    for (const d of (j.dates || [])) {
      const today = new Date().toISOString().slice(0, 10);
      if (d === today) continue; // today already covered by "今日"
      const opt = document.createElement('option');
      opt.value = d;
      opt.textContent = d;
      picker.appendChild(opt);
    }
    picker.value = currentVal; // restore selection if still valid
  } catch(e) { /* silent */ }
}

async function loadTraces() {
  const date = document.getElementById('traces-date-picker').value || null;
  const url = '/api/ops/traces?limit=200' + (date ? '&date=' + date : '');
  try {
    const r = await fetch(url);
    const j = await r.json();
    _traces = j.traces || [];
    _tracesOpen = new Set(); // reset open state when switching dates
    renderTraces();
  } catch(e) {
    console.error('traces fetch error', e);
  }
}

document.addEventListener('DOMContentLoaded', () => {
  document.getElementById('traces-date-picker').addEventListener('change', () => {
    loadTraces();
  });
  // Initial fetch
  fetchData();
});

function renderTraces() {
  const tbody = document.getElementById('traces-body');
  const empty = document.getElementById('traces-empty');
  if (!_traces.length) { tbody.innerHTML = ''; empty.classList.remove('hidden'); return; }
  empty.classList.add('hidden');

  // Save content of currently open rows so we don't re-fetch them
  const savedContent = {};
  for (const id of _tracesOpen) {
    const el = document.getElementById('trace-body-' + id);
    if (el && !el.querySelector('[data-loading]')) savedContent[id] = el.innerHTML;
  }

  tbody.innerHTML = _traces.map((t) => {
    const ts = t.ts ? new Date(t.ts).toLocaleTimeString('zh-CN') : '—';
    const session = (t.session_key || '').replace('fengling-', '').substring(0, 8);
    const user = (t.user || '').substring(0, 40);
    const statusCls = t.status === 'done' ? 'pill-done' : t.status === 'error' ? 'pill-error' : 'pill-running';
    const ms = t.total_ms > 0 ? (t.total_ms / 1000).toFixed(1) + 's' : '—';
    const steps = t.steps_count || 0;
    const reply = (t.reply || t.error || '').substring(0, 50);
    const isOpen = _tracesOpen.has(t.id);
    return `<tr class="trace-row ${isOpen ? 'open' : ''}" onclick="toggleTrace('${t.id}', this)">
      <td class="mono" style="white-space:nowrap;font-size:11px">${ts}</td>
      <td class="mono" style="color:var(--muted);font-size:11px">${session}</td>
      <td>${user}</td>
      <td><span class="pill ${statusCls}">${t.status}</span></td>
      <td style="color:var(--muted)">${ms}</td>
      <td style="text-align:center;color:var(--muted)">${steps}</td>
      <td style="color:var(--muted);font-size:12px">${reply}</td>
    </tr>
    <tr id="trace-detail-${t.id}" style="display:${isOpen ? '' : 'none'}">
      <td colspan="7" style="padding:0">
        <div class="trace-detail open" id="trace-body-${t.id}">
          ${savedContent[t.id] || '<div data-loading style="color:var(--muted);font-size:12px">加载中…</div>'}
        </div>
      </td>
    </tr>`;
  }).join('');

  // Re-fetch content for open rows that had no saved content (e.g. first open)
  for (const id of _tracesOpen) {
    const body = document.getElementById('trace-body-' + id);
    if (body && body.querySelector('[data-loading]')) {
      _fetchTraceDetail(id);
    }
  }
}

async function _fetchTraceDetail(id) {
  const body = document.getElementById('trace-body-' + id);
  if (!body) return;
  try {
    const r = await fetch('/api/ops/traces/' + id);
    const t = await r.json();
    if (t.error) { body.innerHTML = `<div style="color:var(--red)">${t.error}</div>`; return; }
    const steps = t.steps || [];
    if (!steps.length) { body.innerHTML = '<div style="color:var(--muted);font-size:12px">无工具调用，直接回复</div>'; return; }
    body.innerHTML = `<ul class="step-list">${steps.map(s => {
      if (s.type === 'llm') {
        const calls = (s.tool_calls || []).join(', ');
        return `<li class="step-llm">
          <span class="step-tag step-tag-llm">LLM</span>
          第 ${s.round} 轮 · ${s.ms}ms
          ${calls ? ' → 调用: <strong>' + calls + '</strong>' : ' → 直接回复 (' + (s.reply_chars || 0) + ' chars)'}
        </li>`;
      } else {
        const argsStr = s.args ? JSON.stringify(s.args, null, 2) : '';
        const resultStr = s.result || '';
        return `<li class="step-tool">
          <span class="step-tag step-tag-tool">TOOL</span>
          <strong>${s.name}</strong> · ${s.ms}ms · ${s.result_chars || 0} chars
          ${argsStr ? '<div class="step-args">' + escHtml(argsStr) + '</div>' : ''}
          ${resultStr ? '<div class="step-result">' + escHtml(resultStr) + '</div>' : ''}
        </li>`;
      }
    }).join('')}</ul>`;
  } catch(e) {
    body.innerHTML = `<div style="color:var(--red)">加载失败: ${e}</div>`;
  }
}

async function toggleTrace(id, row) {
  const detailRow = document.getElementById('trace-detail-' + id);
  const body = document.getElementById('trace-body-' + id);
  if (detailRow.style.display === 'none') {
    detailRow.style.display = '';
    body.classList.add('open');
    _tracesOpen.add(id);
    await _fetchTraceDetail(id);
  } else {
    detailRow.style.display = 'none';
    _tracesOpen.delete(id);
  }
}

function escHtml(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}

async function loadMemory() {
