async function loadTasksPanel() {
  const treeEl = document.getElementById('tasks-tree');
  const emptyEl = document.getElementById('tasks-empty');
  const hintEl = document.getElementById('tasks-neo4j-hint');
  try {
    const r = await fetch('/api/tasks/tree');
    if (!r.ok) {
        if (r.status === 503) {
            treeEl.innerHTML = '';
            emptyEl.classList.remove('hidden');
            hintEl.textContent = 'Neo4j 离线';
            return;
        }
        throw new Error('HTTP ' + r.status);
    }
    const d = await r.json();
    hintEl.textContent = 'Neo4j 已连接';
    if (!d.tasks || d.tasks.length === 0) {
      treeEl.innerHTML = '';
      emptyEl.classList.remove('hidden');
      return;
    }
    emptyEl.classList.add('hidden');
    treeEl.innerHTML = renderTaskNodes(d.tasks);
  } catch(e) {
    hintEl.textContent = '加载失败: ' + e.message;
  }
}

function renderTaskNodes(tasks) {
  return tasks.map(t => {
    const hasChildren = t.children && t.children.length > 0;
    const statusIcon = getTaskStatusIcon(t.status);
    return `
      <div class="tree-node" data-id="${t.id}">
        <div class="task-row" onclick="toggleTaskNode(this)">
          <span class="toggle-arrow ${hasChildren ? '' : 'placeholder'}">▶</span>
          <span class="status-icon ${t.status}">${statusIcon}</span>
          <span class="task-title">${t.title}</span>
          <span class="state-badge ${t.status}">${t.status}</span>
        </div>
        ${hasChildren ? `<div class="tree-children collapsed">${renderTaskNodes(t.children)}</div>` : ''}
      </div>
    `;
  }).join('');
}

function getTaskStatusIcon(s) {
  switch(s) {
    case 'running': return '●';
    case 'completed': return '✓';
    case 'failed': return '✗';
    case 'waiting': return '⌛';
    default: return '○';
  }
}

function toggleTaskNode(row) {
  const node = row.parentElement;
  const arrow = row.querySelector('.toggle-arrow');
  const children = node.querySelector('.tree-children');
  if (children) {
    const isCollapsed = children.classList.toggle('collapsed');
    arrow.classList.toggle('expanded', !isCollapsed);
  }
}

